args.sparql:
SELECT ?club ?clubLabel ?value WHERE {
  ?club wdt:P118 wd:Q19510 .
  ?club p:P3328/psv:P3328 ?valueNode .
  ?valueNode wikibase:quantityAmount ?value ;
             wikibase:quantityUnit ?unit .
  ?club rdfs:label ?clubLabel .
  FILTER(LANG(?clubLabel) = "en")
}
ORDER BY DESC(?value)
LIMIT 1
